#[async_trait]
impl<R: AuditLogProjectionRepository> AuditLogEventHandler for AuditLogProjector<R> {

    async fn on_created(&self, event: AuditLogCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = AuditLogProjection::new(
            event.id,
            event.user_id,
            event.action,
            event.details,
            event.severity,
            event.ip_address,
            event.user_agent,
            event.session_id,
            event.resource_type,
            event.resource_id,
            event.timestamp,
            event.archived,
            event.archived_at,
            event.archive_location,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: AuditLogUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.action = event.action;
            projection.details = event.details;
            projection.severity = event.severity;
            projection.ip_address = event.ip_address;
            projection.user_agent = event.user_agent;
            projection.session_id = event.session_id;
            projection.resource_type = event.resource_type;
            projection.resource_id = event.resource_id;
            projection.timestamp = event.timestamp;
            projection.archived = event.archived;
            projection.archived_at = event.archived_at;
            projection.archive_location = event.archive_location;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: AuditLogDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

